def safe_access(my_list, index):
    try:
        return my_list[index]
    except IndexError:
        return "Index out of range"

if __name__ == "__main__":
    input_list = list(map(int, input().strip().split()))
    index = int(input().strip())
    result = safe_access(input_list, index)
    print(result)
